queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?clubs a :Clubs .
    ?clubs p:name ?name .
    ?clubs p:Participants ?participants_f .
    FILTER((STR(?participants_f) = "30" || STR(?participants_f) = "30.0"))
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?leadershipprograms a :LeadershipPrograms .
    ?leadershipprograms p:name ?name .
    ?leadershipprograms p:Participants ?participants_f .
    FILTER((STR(?participants_f) = "30" || STR(?participants_f) = "30.0"))
    BIND(?name AS ?o0)
  }
}

